    lineEnd: z.number().int().positive(),
    lineStart: z.number().int().positive(),
    messageId: z.string(),
    strategy: z.literal("exact"),
  })
  .strict();

export const blockTypeSelectorSchema = z
  .object({
    blockType: z.string(),
    strategy: z.literal("block_type"),
